package pe.org.camaracomercioica.protestos.controller; import lombok.RequiredArgsConstructor; import org.springframework.format.annotation.DateTimeFormat; import org.springframework.web.bind.annotation.*; import pe.org.camaracomercioica.protestos.dto.ProtestoResponse; import pe.org.camaracomercioica.protestos.repository.ProtestoRepository; import java.time.LocalDate; import java.util.List; @RestController @RequestMapping("/api/protestos") @RequiredArgsConstructor public class ProtestoController {private final ProtestoRepository repository;@GetMapping("/consulta") List<ProtestoResponse> consultar(@RequestParam(required=false) String documento,@RequestParam(required=false) String nombre,@RequestParam(required=false) Long entidad,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE) LocalDate desde,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE) LocalDate hasta){return repository.consultar(blank(documento),blank(nombre),entidad,desde,hasta).stream().map(p->new ProtestoResponse(p.getId(),p.getNumeroDocumento(),p.getNombreDeudor(),p.getEntidad().getRazonSocial(),p.getTipoTitulo(),p.getMonto(),p.getMoneda(),p.getFechaProtesto(),p.isVigente())).toList();}private String blank(String s){return s==null||s.isBlank()?null:s.trim();}}
